import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";

interface SectionSkeletonProps {
  height?: string;
  background?: "muted" | "default";
  className?: string;
}

/**
 * Generic section-level skeleton for Suspense fallbacks of homepage sections.
 * Replaces repeated `<div className="h-[220px] bg-muted/30 rounded-lg animate-pulse" />`
 * blocks with a consistent shimmer skeleton.
 */
const SectionSkeleton = ({
  height = "h-[220px]",
  background = "muted",
  className,
}: SectionSkeletonProps) => {
  return (
    <section
      className={cn(
        "py-8 sm:py-12 px-4",
        background === "muted" && "bg-secondary/20",
        className
      )}
    >
      <div className="container mx-auto max-w-7xl">
        <Skeleton className={cn("w-full rounded-lg", height)} />
      </div>
    </section>
  );
};

export default SectionSkeleton;
