import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

/**
 * Pulls a daily-rotating background image (with its matching photo story)
 * from the restaurants pool — landmarks + michelin restaurants that have
 * a quality image AND a photo story written for it.
 *
 * Same image+story for all users in the same country for one calendar day.
 */

const countryAlias: Record<string, string> = {
  "United Kingdom": "UK",
  "United States": "USA",
  "South Korea": "Korea",
};

const dayHash = () => Math.floor(Date.now() / 86400000);

export interface DailyHeroImage {
  id: string;
  name: string;
  url: string;
  country: string | null;
  michelin_stars: number | null;
  photo_story_zh: string | null;
  photo_story_en: string | null;
  photo_story_pt: string | null;
}

const parseStars = (v: unknown): number => {
  if (v === "1" || v === 1) return 1;
  if (v === "2" || v === 2) return 2;
  if (v === "3" || v === 3) return 3;
  return 0;
};

export const useDailyHeroImagePool = () => {
  return useQuery({
    queryKey: ["daily-hero-image-pool-v3"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, name, image_url, country, michelin_stars, photo_story_zh, photo_story_en, photo_story_pt")
        .eq("template", "michelin")
        .eq("visible", true)
        .eq("archived", false)
        .eq("image_persist_status", "success")
        .not("image_url", "is", null)
        .not("photo_story_zh", "is", null)
        .not("name", "ilike", "%大使馆%")
        .not("name", "ilike", "%领事馆%")
        .not("name", "ilike", "%Embassy%")
        .not("name", "ilike", "%Consulate%")
        .not("name", "ilike", "%Embaixada%")
        .not("name", "ilike", "%Consulado%")
        .limit(2000);
      if (error) throw error;
      return (data || [])
        .filter((r) => !!r.image_url && !!r.photo_story_zh)
        .map((r) => ({
          id: r.id as string,
          name: r.name as string,
          url: r.image_url as string,
          country: r.country,
          michelin_stars: parseStars((r as any).michelin_stars),
          photo_story_zh: r.photo_story_zh,
          photo_story_en: r.photo_story_en,
          photo_story_pt: r.photo_story_pt,
        })) as DailyHeroImage[];
    },
    staleTime: 1000 * 60 * 60,
    gcTime: 1000 * 60 * 60 * 4,
    retry: 1,
  });
};

export const pickDailyHeroImage = (
  pool: DailyHeroImage[] | undefined,
  country: string | null,
  offset: number = 0,
): DailyHeroImage | null => {
  if (!pool || pool.length === 0) return null;
  const target = country ? countryAlias[country] || country : null;
  // If a target country is specified, ONLY use restaurants from that country.
  // Never cross-pollinate (e.g. Spanish restaurant story under Japan hero).
  // If no global country requested, use entire pool.
  const basePool = target
    ? pool.filter((p) => p.country === target)
    : pool;
  if (basePool.length === 0) return null;

  // Tier by Michelin stars: 3★ > 2★ > 1★ > others
  const byStars = (n: number) => basePool.filter((p) => (p.michelin_stars ?? 0) === n);
  const tiers = [byStars(3), byStars(2), byStars(1), basePool.filter((p) => !p.michelin_stars)];
  const finalPool = (tiers.find((t) => t.length > 0) ?? basePool);

  return finalPool[(dayHash() + offset) % finalPool.length];
};
